import {
  Card,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
} from '@mui/material';
import React from 'react';

export default function TimestampProjectCost({ timestamp }) {
  const formatCurrency = (amount) => {
    // แสดงเฉพาะตัวเลข ไม่แสดงสัญลักษณ์ค่าเงิน
    return new Intl.NumberFormat('th-TH', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(amount || 0);
  };
  return (
    <div className="py-2">
      <Card>
        <div>
          <Table size="small">
            {' '}
            <TableHead>
              <TableRow sx={{ bgcolor: 'primary.main' }}>
                <TableCell colSpan={4} align="center">
                  ค่าแรงพนักงาน (ไม่หักภาษีและประกันสังคม)
                </TableCell>
                {/* <TableCell
                  colSpan={2}
                  align="center"
                  sx={{ bgcolor: 'lightgray' }}
                >
                  ประกันสังคม
                </TableCell> */}
              </TableRow>
              <TableRow sx={{ bgcolor: 'lightgray' }} align="center">
                <TableCell sx={{ bgcolor: 'primary.light' }} align="center">
                  โครงการ
                </TableCell>
                <TableCell sx={{ bgcolor: 'primary.light' }} align="center">
                  ค่าแรง
                </TableCell>
                <TableCell sx={{ bgcolor: 'primary.light' }} align="center">
                  OT
                </TableCell>
                <TableCell sx={{ bgcolor: 'primary.light' }} align="center">
                  รวม
                </TableCell>
                {/* <TableCell align="center">ลูกจ้าง</TableCell>
                <TableCell align="center">นายจ้างสมทบ</TableCell> */}
              </TableRow>
            </TableHead>
            <TableBody>
              {timestamp?.dashboard?.length > 0 ? (
                <>
                  {timestamp.dashboard.map((row) => (
                    <TableRow key={row.id}>
                      <TableCell>{row?.project_number}</TableCell>
                      <TableCell align="right">
                        {formatCurrency(row?.total_salary)}
                      </TableCell>
                      <TableCell align="right">
                        {formatCurrency(row?.total_ot)}
                      </TableCell>
                      <TableCell align="right">
                        {formatCurrency(row?.total_ot + row?.total_salary)}
                      </TableCell>
                      {/* <TableCell align="right">
                        {formatCurrency(row?.contractorCost)}
                      </TableCell>
                      <TableCell align="right">
                        {formatCurrency(row?.employerContribution)}
                      </TableCell> */}
                    </TableRow>
                  ))}
                  {/* สรุปรวมทุกโปรเจค */}
                  <TableRow sx={{ bgcolor: 'primary.light' }}>
                    <TableCell align="center" sx={{ fontWeight: 600 }}>
                      รวมทั้งหมด
                    </TableCell>
                    <TableCell align="right" sx={{ fontWeight: 600 }}>
                      {formatCurrency(
                        timestamp.dashboard.reduce(
                          (sum, row) => sum + (row?.total_salary || 0),
                          0,
                        ),
                      )}
                    </TableCell>
                    <TableCell align="right" sx={{ fontWeight: 600 }}>
                      {formatCurrency(
                        timestamp.dashboard.reduce(
                          (sum, row) => sum + (row?.total_ot || 0),
                          0,
                        ),
                      )}
                    </TableCell>
                    <TableCell align="right" sx={{ fontWeight: 600 }}>
                      {formatCurrency(
                        timestamp.dashboard.reduce(
                          (sum, row) =>
                            sum +
                            ((row?.total_salary || 0) + (row?.total_ot || 0)),
                          0,
                        ),
                      )}
                    </TableCell>
                    {/* <TableCell align="right" sx={{ fontWeight: 600 }}>
                      {formatCurrency(
                        timestamp.dashboard.reduce(
                          (sum, row) => sum + (row?.contractorCost || 0),
                          0,
                        ),
                      )}
                    </TableCell>
                    <TableCell align="right" sx={{ fontWeight: 600 }}>
                      {formatCurrency(
                        timestamp.dashboard.reduce(
                          (sum, row) => sum + (row?.employerContribution || 0),
                          0,
                        ),
                      )}
                    </TableCell> */}
                  </TableRow>
                </>
              ) : (
                <TableRow>
                  <TableCell
                    colSpan={4}
                    align="center"
                    sx={{ color: 'text.secondary', py: 4 }}
                  >
                    ไม่มีข้อมูล
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </div>
      </Card>
    </div>
  );
}
